#include<bits/stdc++.h>
using namespace std;

typedef long long LL;
#define REP(i,n)for(int i=0;i<(n);++i)
#define FOR(i,a,b)for(int i=(a);i<=(b);++i)
#define FIR(i,a,b)for(int i=(a);i>=(b);--i)

const int MOD=998244353;
struct modn{
	int n;
	modn(){}
	modn(LL x){n=(x>=0?(x<MOD?x:x%MOD):(x%MOD+MOD)%MOD);}
	bool operator <(const modn& B){return n<B.n;}
	bool operator ==(const modn& B){return n==B.n;}
	bool operator !=(const modn& B){return n!=B.n;}
	modn& operator +=(const modn& B){n+=B.n;if(n>=MOD)n-=MOD;return *this;}
	modn& operator -=(const modn& B){n-=B.n;if(n<0)n+=MOD;return *this;}
	modn& operator *=(const modn& B){LL x=(LL)n*B.n;n=x<MOD?x:x%MOD;return *this;}
	modn& operator -(){n=MOD-n;return *this;}
	void print()const{printf("%d\n",n);}
};
modn pow_mod(const modn& A,LL x){
	x=(x>=0?(x<(MOD-1)?x:x%(MOD-1)):(x%(MOD-1)+(MOD-1))%(MOD-1));
	modn s=1,t=A;for(;x;x>>=1){if(x&1)s*=t;t*=t;}
	return s;
}

// inverse: the inverse function
// reverse: the reverse of (d|n) and (n|d)
void MT(modn* f,int n,int inv,int rev){
	if(!rev){
		FOR(i,1,n)for(int j=i+i;j<=n;j+=i)
			if(!inv)f[j]+=f[i];else f[j]-=f[i];
	}else{
		FIR(i,n,1)for(int j=i+i;j<=n;j+=i)
			if(!inv)f[i]+=f[j];else f[i]-=f[j];
	}
}

const int maxn=100010;

int n,c,d,q;
modn b[maxn],f[maxn],g[maxn],h[maxn];
void solve(){
	scanf("%d%d%d%d",&n,&c,&d,&q);
	FOR(i,1,n)f[i]=pow_mod(i,c-d);
	MT(f,n,1,0);
	FOR(i,1,n)f[i]=pow_mod(f[i],-1);
	FOR(i,1,n)g[i]=h[i]=pow_mod(i,-d);
	while(q--){
		FOR(i,1,n){int x;scanf("%d",&x);b[i]=x;}
		FOR(i,1,n)b[i]*=g[i];
		MT(b,n,1,0);
		bool fg=1;
		FOR(i,1,n){
			if(b[i].n&&!f[i].n){fg=0;break;}
			b[i]*=f[i];
		}
