#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
#define debug(...) fprintf (stderr, __VA_ARGS__)

#define lep(i, l, r) for (int i = (l), i##_end = (r); i <= i##_end; ++ i)
#define rep(i, r, l) for (int i = (r), i##_end = (l); i >= i##_end; -- i)

char buf[1 << 23], *p1 = buf, *p2 = buf;
inline int getc () {
	return p1 == p2 && (p2 = (p1 = buf) + fread (buf, 1, 1 << 23, stdin), p1 == p2) ? EOF : *p1 ++ ;
}
char __c; bool _f; template <class T> inline void IN (T & x) {
	_f = 0, x = 0; while (__c = getc (), ! isdigit (__c)) if (__c == '-') _f = 1;
	while (isdigit (__c)) x = x * 10 + __c - '0', __c = getc (); if (_f) x = -x;
}

const int mod = 998244353;

inline int mul (int x, int y) { return 1ll * x * y % mod; }
inline int qpow (int x, int y, int r = 1) { for ( ; y; y >>= 1, x = mul (x, x)) if (y & 1) r = mul (r, x); return r; }

inline void sub (int &x, int y) { x -= y; if (x < 0) x += mod; }
inline void pls (int &x, int y) { x += y; if (x >= mod) x -= mod; }
inline int dec (int x, int y) { x -= y; if (x < 0) x += mod; return x; }
inline int add (int x, int y) { x += y; if (x >= mod) x -= mod; return x; }

const int N = 1e5 + 5;

int n, c, d, q, b[N];

// {{{

int cnt, pri[N], idk1[N], idk2[N], mui[N], f[N];
bitset <N> vis;

inline void convolution (int *f) {
	rep (j, cnt, 1) for (int c = n / pri[j]; c; -- c) sub (f[c * pri[j]], f[c]);
}

inline void sieve (int k1, int k2) {
	idk1[1] = idk2[1] = 1, mui[1] = 1;

	lep (i, 2, n) {
		if (! vis[i]) {
			pri[ ++ cnt] = i;
			idk1[i] = qpow (i, k1);
			idk2[i] = qpow (i, k2);
			mui[i] = mod - 1;
		}
		for (int j = 1; j <= cnt && i * pri[j] <= n; ++ j) {
			idk1[i * pri[j]] = mul (idk1[i], idk1[pri[j]]);
			idk2[i * pri[j]] = mul (idk2[i], idk2[pri[j]]);

			vis[i * pri[j]] = true;
			if (! (i % pri[j])) { mui[i * pri[j]] = 0; break ; }
			mui[i * pri[j]] = mod - mui[i];
		}
	}

	memcpy (f, idk2, sizeof f);
	convolution (f);
	lep (i, 1, n) f[i] = qpow (f[i], mod - 2);
}

// }}}

inline bool work () {
	convolution (b);
	lep (i, 1, n) {
		if (b[i] && ! f[i]) return false;
		b[i] = mul (b[i], f[i]);
	}
	lep (i, 1, n) {
		int ret = 0;
		for (int d = 1; d <= n / i; ++ d) pls (ret, mul (mui[d], b[d * i]));
		b[i] = ret;
	}
	return true;
}

signed main () {
	IN (n), IN (c), IN (d), IN (q);
	c %= (mod - 1);
	d %= (mod - 1);
	sieve (mod - 1 - d, (c - d + mod - 1) % (mod - 1));

	while (q -- ) {
		lep (i, 1, n) IN (b[i]), b[i] = mul (b[i], idk1[i]);
		bool ret = work ();

		if (! ret) puts ("-1");
		else lep (i, 1, n) printf ("%d%c", mul (b[i], idk1[i]), i == n ? '\n' : ' ');
	}
	return 0;
}

