	inline ld X(int x) {return pf[x];}
	inline ld Y(int x) {return lf[x];}
	inline ld slope(int x1, int x2)
	{return (X(x1) == X(x2)) ? (Y(x2) > Y(x1) ? 1e60 : -1e60) : ((Y(x1) - Y(x2)) / (X(x1) - X(x2)));}
	
	inline void qr(int &x, char ch = 0)
	{
