	}

	void Update(int root,int l,int r,int o,ll num)
	{
		if(l==r)
			Refresh(root,num);
		else{
			int mid=(l+r)/2;
			if(o<=mid)
				Update(lson[root],l,mid,o,num);
			else
				Update(rson[root],mid+1,r,o,num);
			Maintain(root);
		}
	}
};

Segment T,P;

namespace FindCircle
{	
	void Clear()
	{
		memset(used,false,sizeof(used));
	}
	
	bool Dfs(int u,int f)
	{
		used[u]=true;
		for(int i=0;i<G[u].size();i++){
			int v=G[u][i].to;
			if(v==f)
				continue;
			fa[v]=u;
			if(used[v]){
				Circle[CircleCnt=1]=v;
				return true;
			}
			if(Dfs(v,u))
				return true;
		}
		return false;
	}
			
	void GetCircle()
	{
		Dfs(1,-1);
		int from=Circle[1],u=from;
		OnCircle[u]=true;
		while(fa[u]!=from){
			Circle[++CircleCnt]=fa[u];
			OnCircle[fa[u]]=true;
			u=fa[u];
		}
	}
};

namespace ProcessOnCircle
{
	void Dfs(int u,int fa,int& p)
	{
		for(int i=0;i<G[u].size();i++){
			Edge e=G[u][i];
			if(OnCircle[e.to]||e.to==fa)
				continue;
			DisOnTree[e.to]=DisOnTree[u]+e.w;
			if(DisOnTree[e.to]>DisOnTree[p])
				p=e.to;
			Dfs(e.to,u,p);
		}
	}
	
	void GetDiameter(int u,int f,int CircleNum)
	{
		for(int i=0;i<G[u].size();i++){
			Edge e=G[u][i];
			if(e.to==f||(OnCircle[e.to]&&e.to!=CircleNum))
				continue;
			DisOnTree[e.to]=DisOnTree[u]+e.w;
			Diameter=max(Diameter,DisOnTree[e.to]);
			GetDiameter(e.to,u,CircleNum);
		}
	}
	
	void ProcessOnTree()
	{
		for(int i=1;i<=CircleCnt;i++){
			int u=Circle[i];
			int p=u;
			Dfs(u,-1,p);
			MaxDis[u]=DisOnTree[p];
			DisOnTree[p]=0;
			GetDiameter(p,-1,u);
		}
	}
	
	void GetPredis()
	{	
		for(int i=1;i<=CircleCnt;i++){
			int u=Circle[i];
			for(int j=0;j<G[u].size();j++){
				Edge e=G[u][j];
				if(e.to==Circle[(i%CircleCnt)+1]){
					DisOnCircle[(i%CircleCnt)+1]=e.w;
					break;
				}
			}
		}
		SumOnCircle[1]=0;
		for(int i=2;i<=CircleCnt;i++)
			SumOnCircle[i]=SumOnCircle[i-1]+DisOnCircle[i];
		for(int i=1;i<=CircleCnt;i++)
			Present[i]=SumOnCircle[i]+MaxDis[Circle[i]];
		T.BuildTree(T.root,1,CircleCnt,Present);
		for(int i=1;i<=CircleCnt;i++)
			Present[i]=MaxDis[Circle[i]]-SumOnCircle[i];
		P.BuildTree(P.root,1,CircleCnt,Present);
	}
	
	void GetAns()
	{
		ll ans=INF;
		for(int i=1;i<=CircleCnt;i++){
			if(T.tot[T.root]!=P.tot[P.root])
				ans=min(ans,T.Maxw[T.root]+P.Maxw[P.root]);
			else
				ans=min(ans,max(T.Maxw[T.root]+P.Second[P.root],T.Second[T.root]+P.Maxw[P.root]));
			SumOnCircle[i]=SumOnCircle[i>1?i-1:CircleCnt]+DisOnCircle[i];
			T.Update(T.root,1,CircleCnt,i,SumOnCircle[i]+MaxDis[Circle[i]]);
			P.Update(P.root,1,CircleCnt,i,MaxDis[Circle[i]]-SumOnCircle[i]);
		}
		printf("%.1lf\n",double(max(Diameter,ans))/2);
	}
}

void AddEdge(int from,int to,int w)
{
	G[from].push_back(Edge(from,to,w));
	G[to].push_back(Edge(to,from,w));
}

