void Get_Height()
{
	for (int i=1;i<=n;i++) rank[sa[i]]=i;
	for (int i=1,x=0;i<=n;i++)
	{
		if (x) x--;
		int j=sa[rank[i]-1];
		while (i+x<=n && j+x<=n && s[i+x]==s[j+x]) x++;
