		if (i) if (a[i]>0) submax1[i]=submin[i]=a[i];else negmax1[i]=negmin[i]=a[i];
		tot[i]=1;
		ansb[i]=-inf;
	}
	tot[0]=0;
	ansb[n+1]=-inf;
	sort(I+1,I+1+n,cmp);
	for (int i=n,w=1;i>=0;i--)
	{
		ansa[i]=ansa[i+1];
		ansb[i]=ansb[i+1];
		while (w<=n && I[w].h==i)
			Update(sa[I[w].id-1],sa[I[w].id],i),w++;
	}
}

void Print()
{
	for (int i=0;i<n;i++)
	if (ansa[i]) printf("%lld %lld\n",ansa[i],ansb[i]);
		else printf("0 0\n");
}

int main()
{
	Init();
	Work();
	Print();
	return 0;
}

