void Rsort()
{
	for(int i = 0;i <= m;++ i)tex[i] = 0;
	for(int i = 1;i <= n;++ i)tex[Rank[y[i]]] ++;
	for(int i = 1;i <= m;++ i)tex[i] += tex[i-1];
	for(int i = n;i >= 1; -- i)SA[tex[Rank[y[i]]] --] = y[i];
}
bool cmp(int *f,int a,int b,int c){return f[a] == f[b] && f[a+c] == f[b+c];}
bool cmp2(int a,int b){return h[a] == h[b] ? a > b : h[a] > h[b];}
void da()
{
	scanf("%d",&n); m = 128;
	scanf("%s",s + 1); 
	Rep(i,n)scanf("%d",&val[i]);
	for(int i = 1;i <= n;++ i)Rank[i] = s[i],y[i] = i;
	Rsort();
	for(int w = 1, p = 0;p < n;w <<= 1,m = p)
	{
		p = 0;for(int i = n - w + 1;i <= n;++ i)y[++ p] = i;
		for(int i = 1;i <= n;++ i)if(SA[i] > w)y[++ p] = SA[i] - w;
		Rsort();swap(Rank,y);Rank[SA[1]] = p = 1;
		for(int i = 2;i <= n;++ i)Rank[SA[i]] = cmp(y,SA[i],SA[i-1],w) ? p : ++ p;
	}
	int j,k = 0;
	for(int i = 1;i <= n;h[Rank[i ++]] = k)
		for(k = max(k - 1,0),j = SA[Rank[i] - 1];s[j + k] == s[i + k];++ k);
