void Merge(int x,int y)
{
	if(sz[x] > sz[y])swap(x,y);
	sz[y] += sz[x];
	Min[y] = min(Min[y],Min[x]);
	Max[y] = max(Max[y],Max[x]);
	fa[x] = y;
}
