		num[0] = N;
		while (d[s]<N) {
			if (x==t) {
				flow += augment(s, t);
				x = s;
			}
			bool ok = false;
			for (int i = cur[x]; i>=0; i = G.nxt[i]) {
				edge &e = G.E[i];
