#include <bits/stdc++.h>
#define rep(i, x, y) for (int i = x; i <= y; i++)
using namespace std;

typedef long long ll;
const int N = 1e5 + 10;
int n, m, K, t, fa[N];
ll ans[N], dis[N], lst;

ll gcd(ll x, ll y) {
    return !y ? x : gcd(y, x % y);
}

int getfa(int x) {
    if (fa[x] == x) return x;
    int t = fa[x];
    fa[x] = getfa(fa[x]);
    dis[x] += dis[t];
    return fa[x];
}

signed main() {
    cin >> n >> m >> K >> t;
    rep(i, 1, n) fa[i] = i;
    rep(i, 1, m) {
        int p, u, v, a, b; ll w;
        scanf("%d%d%d%lld%d%d", &p, &u, &v, &w, &a, &b);
        u = (u + (a & lst) - 1) % n + 1;
        v = (v + (b & lst) - 1) % n + 1;
        if (!p) {
            int x = getfa(u), y = getfa(v);
            if (x == y) {
                ll D = dis[u] - dis[v] - w;
                ans[x] = gcd(ans[x], abs(D));
            } else {
                fa[x] = y;
                dis[x] = dis[v] + w - dis[u];
                ans[y] = gcd(ans[x], ans[y]);
            }
        } else {
            int x = getfa(u), y = getfa(v);
            lst = (lst << 1) & ((1 << 30) - 1);
            if (x != y) puts("0");
            else {
                ll D = abs(w - dis[u] + dis[v]);
                if (!ans[y]) {
                    if (!D) puts("1"), lst |= 1;
                    else puts("0");
                } else {
                    if (D % ans[y]) puts("0");
                    else puts("1"), lst |= 1;
                }
            }
        }
    }
    return 0;
}

