					pii A(s[i].x+dx,s[i].y+dy);
					if(out(A) || noir.count(A) || blanc.count(A))continue;

					blanc[A]=++tot;
					s[tot]=A;
				}
		}
	}

	int spj()
	{
		ll cntw=(ll)n*m-c;
		if(cntw<=1)return -1;
		else if(cntw==2)
		{
			if(n*m==2)return -1;
			pii A=s[c+1],B=s[c+2];
			int dis=std::abs(A.x-B.x)+std::abs(A.y-B.y);
			if(dis==1)return -1;
		}

		if(std::min(n,m)==1)
		{
			return 1;
		}

		return 0;
	}

