		for(int k=0,q;k<4;k++)
		{
			B=pii(A.x+mv[k][0],A.y+mv[k][1]);
			if(out(B))continue;
			if(!blanc.count(B))continue;
			q=blanc[B];
			if(q==h)continue;

			if(bel[q])check_min(dfn[q],lowp);
			else
			{
				cntson++;
				check_min(lowq=dfs(q,p),lowp);

				if(lowq>=dfn[p] && h!=-1)iscut[p]=1;
			}
		}
		
		if(h==-1 && cntson>1)iscut[p]=1;

		return lowp;
	}

