		for(int i=1;i<=tot;i++)bel[i]=0,iscut[i]=0;
		cnt_block=clk=0;

		for(int i=c+1;i<=tot;i++)
			if(!bel[i])cnt_block++,dfs(i);

		if(disconnected())printf("0\n");
		else if(findit() || tmp==1)printf("1\n");
		else printf("2\n");
	}
}

