#include<bits/stdc++.h>
#define For(i,l,r) for(int i = (l),i##end = (r);i <= i##end;i++)
#define Fordown(i,r,l) for(int i = (r),i##end = (l);i >= i##end;i--)
using namespace std;
typedef long long ll;
const int INF = 1e9;
const int N = 1e5 + 10,Lim = 1e5;
struct node{
	int a,s,c,x;
}Veg[N];
struct Vegs{
	int val,id,type;
	bool operator < (const Vegs &rhs) const {
		return val < rhs.val;
	}
};
priority_queue <Vegs> Q,Tmp;
priority_queue < int,vector<int>,greater<int> > P;
vector <int> Time[N];
int Used[N];
ll ans[N];
inline int read(){
	int x = 0,flag = 1;
	char ch = getchar();
	while(!isdigit(ch) && ch != '-')ch = getchar();
	if(ch == '-')flag = -1,ch = getchar();
	while(isdigit(ch))x = (x<<3)+(x<<1)+ch-'0',ch = getchar();
	return x*flag;
}
inline int Getres(int id,int t){
	return max(0ll,Veg[id].c - 1ll * (t - 1) * Veg[id].x);
}
int main(){
#ifndef ONLINE_JUDGE
	freopen("UOJ318.in","r",stdin);
	freopen("UOJ318.out","w",stdout);
#endif
	int n = read(),m = read(),q = read();
	For(i,1,n){
		int a = read(),s = read(),c = read(),x = read();
		Veg[i] = (node){a,s,c,x};
		if(x == 0)Time[Lim].push_back(i);
		else Time[min(Lim,(c - 1) / x + 1)].push_back(i);
	}
	int sum = 0;
	Fordown(i,Lim,1){
		For(j,0,Time[i].size() - 1){
			Q.push((Vegs){Veg[Time[i][j]].a + Veg[Time[i][j]].s,Time[i][j],1});
			Q.push((Vegs){Veg[Time[i][j]].a,Time[i][j],0});
		}
		int res = m;
		int tot = 0;
		while(res && !Q.empty()){
			tot++;
			Vegs t = Q.top();Q.pop();
			if(t.type == 0){
				int rest = Getres(t.id,i) - Used[t.id];Used[t.id] += min(rest,res);
				if(rest > res)ans[Lim] += 1ll * t.val * res,res = 0;
				else ans[Lim] += 1ll * t.val * rest,res -= rest;
				if(Veg[t.id].x || Used[t.id] < Veg[t.id].c)Tmp.push((Vegs){t.val,t.id,0});
			}
			else{
				int rest = Getres(t.id,i) - Used[t.id];
				if(rest)ans[Lim] += t.val,Used[t.id]++,res--;
			}
		}
		sum += res;
		while(Tmp.size())Q.push(Tmp.top()),Tmp.pop();
	}
	For(i,1,n){
		if(Used[i])P.push(Veg[i].a + Veg[i].s);
		For(j,2,Used[i])P.push(Veg[i].a);
	}
	Fordown(i,Lim - 1,1){
		ans[i] = ans[i + 1];int cnt;
		if(sum > m)sum -= m,cnt = 0;
		else cnt = m - sum,sum = 0;
		For(j,1,cnt)ans[i] -= P.top(),P.pop();
