#include <cassert>
typedef long long LL;
const int MAXN = 3e5+10;
struct Seg_tree{
	int Sum;
	LL Pos;
	Seg_tree* lch;
	Seg_tree* rch;

	Seg_tree(int,int);
	Seg_tree(int,int,LL*);

	LL Delete(int,int,int);
	void Insert(int,LL,int,int);
	LL Inquire(int,int,int);
};

Seg_tree* st[MAXN];
int clk[MAXN];
int clkC;
LL A[MAXN*2];
int N,M,K,x,y;
LL t1,t2;

inline int Calc(Seg_tree* u,int l,int r){
	int R = std::min(M-1,r);
	int t = (r && l <= R ? R-l+1 : 0);
	if(u == NULL) return t;
	return u->Sum;
}

int main(){
	scanf("%d%d%d",&N,&M,&K);
	for(int i = 1; i <= N; ++i) A[i] = 1LL*i*M;
	Seg_tree C(1,N+K,A);
	for(int i = 1; i <= K; ++i){
		scanf("%d%d",&x,&y);
		if(y == M){
			t1 = C.Delete(x,1,N+K);
			C.Insert(N+(++clkC),t1,1,N+K);
