	this->Sum = Calc(0,l,r);
	this->Pos = l;
	this->lch = NULL;
	this->rch = NULL;
}
Seg_tree::Seg_tree(int l,int r,LL* A){
	this->Pos = 0;
	if(l == r){
		this->Pos = A[l];
		this->Sum = (A[l] > 0);
		this->lch = NULL;
		this->rch = NULL;
		return;
	}
	int mid = (l+r)>>1;
	this->lch = new Seg_tree(l,mid,A);
	this->rch = new Seg_tree(mid+1,r,A);
	this->Sum = this->lch->Sum + this->rch->Sum;
}

