	}else{
		if(this->rch == NULL) this->rch = new Seg_tree(mid+1,r);
		return this->rch->Delete(k-lcnt,mid+1,r);
	}
}

void Seg_tree::Insert(int x,LL v,int l,int r){
	// assert(x <= r);
	++this->Sum;
	if(l == r) return (void)(this->Pos = v);
	int mid = (l+r)>>1;
	if(x <= mid){
		if(this->lch == NULL) this->lch = new Seg_tree(l,mid);
		this->lch->Insert(x,v,l,mid);
	}else{
		if(this->rch == NULL) this->rch = new Seg_tree(mid+1,r);
		this->rch->Insert(x,v,mid+1,r);
