int ntot=0;

struct Tree
{
	int num;//col=0 row[i]=i
	int size;//m-1 or n ,half the real size
	Node *root;
	inline void buildson(Node *p)
	{
		int mid=(p->l+p->r)>>1;
		Node *son;
		if(!p->ch[0])
		{
			p->ch[0]=&pool[++ntot];
			son=p->ch[0];
			son->l=p->l;son->r=mid;
			if(son->l<=size)son->sum=mid-p->l+1,son->full=1;
			else son->sum=son->full=0;
			son->ch[0]=son->ch[1]=NULL;
			if(son->l==son->r && son->l<=size)
			{
				if(num)son->val=(ll)(num-1)*m+son->l;
				else son->val=(ll)son->l*m;
			}
			else son->val=0;
		}
		if(!p->ch[1])
		{
			p->ch[1]=&pool[++ntot];
			son=p->ch[1];
			son->l=mid+1;son->r=p->r;
			if(son->l<=size)son->sum=p->r-mid,son->full=1;
			else son->sum=son->full=0;
			son->ch[0]=son->ch[1]=NULL;
			if(son->l==son->r && son->l<=size)
			{
				if(num)son->val=(ll)(num-1)*m+son->l;
				else son->val=(ll)son->l*m;
			}
			else son->val=0;
		}
	}
	
	inline void update(Node *p)
	{
		if(p->ch[1]->full)p->full=1;
		p->sum=p->ch[0]->sum+p->ch[1]->sum;
	}
	
	void del(Node *p,int x)
	{
		if(p->l==p->r)
		{
//if(!p->sum)cerr<<"NTT"<<endl;
			p->sum=p->val=p->full=0;
			return;
		}
		buildson(p);
		if(x<=p->ch[0]->sum)del(p->ch[0],x);
		else del(p->ch[1],x-p->ch[0]->sum);
		update(p);
	}
	
	void insert(Node *p,ll val)
	{
//printf("[%d,%d]:%d %d\n",p->l,p->r,p->sum,p->full);
		if(p->l==p->r)
		{
//if(p->sum)cerr<<"ERR"<<endl;
			p->sum=p->full=1;p->val=val;
			return;
		}
		buildson(p);
		if(!p->ch[0]->full && !p->ch[1]->sum)insert(p->ch[0],val);
		else insert(p->ch[1],val);
		update(p);
	}
	
	ll find(Node *p,int x)
	{
		buildson(p);
		if(p->l==p->r)return p->val;
		if(x<=p->ch[0]->sum)return find(p->ch[0],x);
		return find(p->ch[1],x-p->ch[0]->sum);
	}
	
