}

ll getrev(ll x, ll y) {
	ll a, b;
	exgcd(x, a, y, b);
	return (a % y + y) % y;
}

ll Solve(ll A, ll B, ll C) {
	ll g = gcd(A, C);
	if(B % g) return 1e18;
	A /= g, B /= g, C /= g;
	ll r = getrev(A, C);
	return mul(r, B, C);
}

ll Solve() {
	S.clear();
	scanf("%d%d", &n, &m);
	for(int i = 1; i <= n; i++) scanf("%lld", &a[i]);
	for(int i = 1; i <= n; i++) scanf("%lld", &p[i]);
	for(int i = 1; i <= n; i++) scanf("%lld", &atk[i]);
	for(int i = 1; i <= m; i++) {
		ll x;
		scanf("%lld", &x);
		S[x]++;
	}
	ll mn = 0;
	A1 = 0, B1 = 1;
	for(int i = 1; i <= n; i++) {
		ll C = p[i], B = a[i];
		map <ll, int>::iterator it = S.lower_bound(a[i] + 1);
		if(it != S.begin()) it--;
		ll A = it->first;
		if(!--it->second) S.erase(it);
		S[atk[i]]++;
		mn = max(mn, (B - 1) / A + 1);
		ll g = gcd(A, C);
		if(B % g == 0) A /= g, B /= g, C /= g; else return -1;
		ll A2 = mul(getrev(A, C), B, C), B2 = C;
		ll t1 = Solve(B1, A2 - A1, B2);
		if(t1 == 1e18) return -1;
		ll l = B1 / gcd(B1, B2) * B2;
		A1 = (mul(t1, B1, l) + A1) % l;
		B1 = l;
	}
	A1 = (A1 % B1 + B1) % B1;
	if(mn > A1) {
		A1 += (mn - A1) / B1 * B1;
		while(A1 < mn) A1 += B1;
	}
	return A1;
}

