    for (int i = 1; i <= K; ++i) fact[i] = 1l * fact[i - 1] * i % P;
    factinv[K] = pow(fact[K], P - 2);
    for (int i = K; i >= 1; --i) factinv[i - 1] = 1l * factinv[i] * i % P;
    auto binom = [&] (int n, int m) -> int {
      if (min(n, m) < 0 || n < m) return 0;
