#define lc (o << 1)
#define rc (o << 1 | 1)
typedef long long ll;
const int N = 7e4 + 5, M = 1.5e5 + 5;
int n, m, w, h, x[N], y[N], t[M], L[M], R[M], D[M], U[M]; uint dis[N];
std::bitset<N> vis;
std::vector<int> G[N];
struct node {
	int y, id;
	bool operator < (const node &o) const {
		return y != o.y ? y < o.y : id < o.id;
	}
};
std::set<node> data[N * 4];
int pos[N * 4];
void build(int o, int l, int r) {
	if (l == r) { pos[l] = o; return; }
	int mid = l + r >> 1;
	build(lc, l, mid), build(rc, mid + 1, r);
}
void ins(int o, int l, int r, int x, int y, int id) {
	data[o].insert({y, id});
	if (l == r) return;
	int mid = l + r >> 1;
	x <= mid ? ins(lc, l, mid, x, y, id) : ins(rc, mid + 1, r, x, y, id);
}
void del(int o, int l, int r, int x, int y, int id) {
	data[o].erase(data[o].find({y, id}));
	if (l == r) return;
	int mid = l + r >> 1;
	x <= mid ? del(lc, l, mid, x, y, id) : del(rc, mid + 1, r, x, y, id);
}
struct Qnode {
	int p, id; uint dis;
	bool operator < (const Qnode &o) const {
		return dis > o.dis;
	}
};
std::priority_queue<Qnode> Q;
void relax(int o, int l, int r, int L, int R, int p, uint x) {
	if (L <= l && r <= R) {
		Q.push({p, o, x});
		return;
	}
	int mid = l + r >> 1;
	if (L <= mid) relax(lc, l, mid, L, R, p, x);
	if (mid < R) relax(rc, mid + 1, r, L, R, p, x);
}
int main() {
	scanf("%d%d%d%d", &n, &m, &w, &h);
	build(1, 1, w);
	for (int i = 1; i <= n; i++) {
		scanf("%d%d", &x[i], &y[i]);
		ins(1, 1, w, x[i], y[i], i);
	}
	for (int i = 1, id; i <= m; i++) {
		scanf("%d%d%d%d%d%d", &id, &t[i], &L[i], &R[i], &D[i], &U[i]);
		G[id].push_back(i);
	}
	for (int i = 1; i <= n; i++) dis[i] = INT_MAX;
	D[0] = U[0] = y[1];
	Q.push({0, pos[x[1]], dis[1] = 0});
	while (!Q.empty()) {
		Qnode tmp = Q.top(); Q.pop();
		int l = D[tmp.p], r = U[tmp.p];
		auto it = data[tmp.id].lower_bound({l, -1});
		std::vector<int> vec;
		for (; it != data[tmp.id].end() && it->y <= r; it++)
			vec.push_back(it->id);
		for (int u : vec) {
			if (vis[u]) continue;
			dis[u] = tmp.dis; vis[u] = 1;
			for (int i : G[u])
				relax(1, 1, w, L[i], R[i], i, dis[u] + t[i]);
			del(1, 1, w, x[u], y[u], u);
		}
	}
	for (int i = 2; i <= n; i++)
		printf("%u\n", dis[i]);
	return 0;
}

