		if(n<m)return F;
		poly rF=F,rG=G;
		rF.reverse();rF.resize(n-m+1);
		rG.reverse();rG.resize(n-m+1);
		poly Q=rF*inv(rG);Q.resize(n-m+1);Q.reverse();
		poly R=F-G*Q;R.resize(m);
		return R;
	}
