    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++) inv[i]=qpow(i,n-2,n);
    for(int i=-min(n,B);i<=B && i<=n;i++) for(int j=1;j<=T && j<=n;j++) {
        int val=(1ll*i*inv[j]%n+n)%n;
        if(!ab[val].second) ab[val]={i<0? i+n:i,j};
    }
    for(int i=0;i<n;i++) scanf("%d",&a[i]);
    for(int i=1;i<=q;i++) {
        int x,k,l;
