#define cout cerr
long long read(){
  long long q=0,w=1;
  char ch=getchar();
  while(ch>'9' || ch<'0'){if(ch=='-')w=-1;ch=getchar();}
  while(ch>='0'&&ch<='9'){q=q*10+(ch-'0');ch=getchar();}
  return q*w;
}
void write(LL x){
  if(x<0){putchar('-');x=(-x);}
  if(x>9)write(x/10);
  putchar('0'+x%10);
}
void writeln(LL x){write(x);puts("");}
void writecs(LL x){write(x);putchar(' ');}
LL qpow(LL a,LL b,LL p){
  LL ans=1;
  while(b){
    if(b&1)ans=(ans*a)%p;
    b>>=1;a=(a*a)%p;
  }
  return ans;
}
const long long mod = 998244353;
void addmod(LL &x,LL y){x+=y;if(x>=mod)x-=mod;}
void submod(LL &x,LL y){x-=y;if(x<0)x+=mod;}
LL domod(LL x){
  if(x<0)x+=mod;
  if(x>=mod)x-=mod;
  return x;
}
LL inv(LL x){return qpow(x,mod-2,mod);}
namespace Math{
  const long long N = 500+95;
  long long Fac[N],Inv[N];
  void init(LL n){
    Fac[0]=1;
    for(LL i=1;i<=n;i++)Fac[i]=(Fac[i-1]*i)%mod;
    Inv[n]=qpow(Fac[n],mod-2,mod);
    for(LL i=n-1;i>=0;i--)Inv[i]=(Inv[i+1]*(i+1))%mod;
    return ;
  }
  LL C(LL n,LL k){
    if(n<0||k<0||n<k)return 0;
    return (Fac[n]*Inv[k]%mod*Inv[n-k])%mod;
  }
}
using Math::C;
