const long long N = 500+95;
long long m,n,a[N],pw[N],dp[N];
vector<LL>vec;LL ps[N][N],c[N];
bool cmp(LL x,LL y){return x<y;}
LL _C(LL n,LL k){
  //  cout<<" n = "<<n<<" k = "<<k<<endl;
  if(n<0||k<0||n<k)return 0;
  LL up=1,dn=1;
  for(LL i=1;i<=k;i++){
    up=(up*(n-i+1))%mod;
    dn=(dn*i)%mod;
  }
  //  cout<<" up = "<<up<<" dn = "<<dn<<endl;
  return up*inv(dn)%mod;
}
