  for(LL i=1;i<=n;i++)vec.push_back(a[i]);
  vec.push_back(inf);vec.push_back(0);
  sort(vec.begin(),vec.end(),cmp);
  vec.erase(unique(vec.begin(),vec.end()),vec.end());
  Math::init(n+5);dp[n+1]=1;
  for(LL x=SZ(vec)-2;x>=0;x--){
    LL l=vec[x],r=vec[x+1];
    LL cnt=max(min(r,m)-l,0ll);
    //    cout<<" x = "<<x<<" l = "<<l<<" r = "<<r<<" cnt = "<<cnt<<endl;
    if(!cnt)continue;
    for(LL k=0;k<=n+1;k++)c[k]=_C(cnt,k);
    /*    for(LL k=0;k<=n+1;k++)
      cout<<c[k]<<" ";
