      /*      cout<<" sum : "<<sum<<endl;
      for(LL k=0;k<=n;k++)
	cout<<ps[sum][k]<<" ";
      cout<<endl;*/
    }
    for(LL i=1;i<=n;i++){
      if(a[i]<=l)continue;
      LL sum=0;
      for(LL j=i+1;j<=n+1;j++){
	//	cout<<" i = "<<i<<" j = "<<j<<" sum = "<<sum<<" ps = "<<ps[sum][sum]<<" dp[i] = "<<dp[i]<<endl;
	addmod(dp[i],dp[j]*ps[sum][sum]%mod);
	//	cout<<"   then: dp[i] = "<<dp[i]<<" dp[j]*ps[sum][sum] = "<<dp[j]*ps[sum][sum]<<endl;
	if(a[j]>l)sum++;
      }
    }
    /*    for(LL i=1;i<=n+1;i++)
      cout<<dp[i]<<" ";
    cout<<endl;*/
  }
  LL ans=0;
  for(LL i=1;i<=n+1;i++)
    addmod(ans,dp[i]);
  writeln(ans);
  return 0;
}

