    dis[s] = 0, q.push(s);
    while (!q.empty()) {
      int u(q.front());
      q.pop();
      for (int v : G[u]) {
        if (dis[v] > dis[u] + 1)
          dis[v] = dis[u] + 1, q.push(v);
      }
    }
  }

  void main() {
    ios::sync_with_stdio(false);
    cin >> n >> m >> k;
    for (int i(2); i <= n; ++i)
      cin >> w[i];
    for (int i(0); i <= m; ++i) {
      int x, y;
      cin >> x >> y;
      G[x].push_back(y);
      G[y].push_back(x);
    }
    for (int i(1); i <= n; ++i)
      search(dis[i], i);
    for (int i(2); i <= n; ++i)
      for (int j(2); j <= n; ++j) {
