			}
		}
	}
	if (count(a.begin(), a.end(), 1) * 2 < n) {
		res.emplace_back(0, n - 1);
		for (int &x : a) {
			x ^= 1;
		}
	}
	for (int i = 0; i < n; i++) {
		if (a[i] == 0) continue;
		bool good = 0;
		for (int j = 0; i + (1 << j) < n; j++) {
			for (int k = j + 1; i + (1 << j) + (1 << k) < n; k++) {
				if (a[i] && a[i + (1 << j)] && a[i + (1 << k)] && a[i + (1 << j) + (1 << k)]) {
					res.emplace_back(i, (1 << j) | (1 << k));
					good = 1;
					a[i + (1 << j)] = a[i + (1 << k)] = a[i + (1 << j) + (1 << k)] = 0;
					break;
				}
			}
			if (good) break;
		}
