		for (int i=0;i<=n;++i) for (int j=0;j<(1<<n);++j) f[i][j]=g[i][j]=0;
		for (int i=0;i<(1<<n);++i) f[pc(i)][i]=F[i];
		for (int i=0;i<=n;++i) fwt (f[i],(1<<n),1);
		int iv=quip(F[0],mod-2);
		for (int S=1;S<(1<<n);++S) {
			g[0][S]=iv;
			for (int i=1;i<=n;++i) {
				for (int j=0;j<i;++j) if (f[i-j][S] && g[j][S]) add (g[i][S],mod-1ll*g[j][S]*f[i-j][S]%mod);
				g[i][S]=1ll*g[i][S]*iv%mod;
			}
		}
		for (int i=1;i<=n;++i) fwt (g[i],(1<<n),-1);
		G[0]=iv; for (int i=1;i<(1<<n);++i) G[i]=g[pc(i)][i];
	}
	inline void ln (int n,int *F,int *G) {
		for (int i=0;i<=n;++i) for (int j=0;j<(1<<n);++j) f[i][j]=g[i][j]=0;
		for (int j=0;j<(1<<n);++j) f[pc(j)][j]=F[j];
		f[0][0]=1;
		for (int i=0;i<=n;++i) fwt(f[i],(1<<n),1);
		for (int S=0;S<(1<<n);++S) {
			for(int i=0;i<=n;++i) ff[i]=f[i][S];
			for (int i=1,sum;i<=n;++i) {
				gg[i]=ff[i],sum=0;
				for (int j=1;j<i;++j) if (ff[i-j] && gg[j]) add(sum,1ll*j*gg[j]%mod*ff[i-j]%mod);
				add(gg[i],mod-1ll*sum*Inv[i]%mod);
			}
			for(int i=0;i<=n;++i) g[i][S]=gg[i];
		}
		for (int i=0;i<=n;++i) fwt (g[i],(1<<n),-1);
		for (int j=0;j<(1<<n);++j) G[j]=g[pc(j)][j];
	}
	inline void exp (int n,int *F,int *G,bool flg=0) {
		int N=(1<<n);
		for (int i=0;i<=n;++i) for (int j=0;j<N;++j) f[i][j]=g[i][j]=0;
		for (int j=0;j<N;++j) f[pc(j)][j]=F[j];
		for (int i=0;i<=n;++i) fwt(f[i],N,1);
		for (int S=0;S<N;++S) {
			for(int i=0;i<=n;++i) ff[i]=f[i][S];
			gg[0]=1;
			for (int j=1;j<=n;++j) ff[j]=1ll*ff[j]*j%mod;
			for (int i=1;i<=n;++i) {
				ll tp=0;
				for (int j=1;j<=i;++j) if (ff[j] && gg[i-j]) tp+=1ll*ff[j]*gg[i-j]%mod;
				gg[i]=tp%mod*Inv[i]%mod;
			}
			for(int i=0;i<=n;++i) g[i][S]=gg[i];
		}
		if (flg) return ;
		for (int i=0;i<=n;++i) fwt (g[i],N,-1);
		for (int j=0;j<N;++j) G[j]=g[pc(j)][j];
	}
	inline void mul (int n,int F[],int G[],int H[],bool flg=0) {
		if (!flg) {
			for (int i=0;i<=n;++i) for (int j=0;j<(1<<n);++j) f[i][j]=g[i][j]=0;
			for (int i=0;i<(1<<n);++i) f[pc(i)][i]=F[i],g[pc(i)][i]=G[i];
		    for (int i=0;i<=n;++i) fwt (f[i],1<<n,1),fwt (g[i],1<<n,1);
		}
		else {
			for (int i=0;i<=n;++i) for (int j=0;j<(1<<n);++j) f[i][j]=0;
			for (int i=0;i<(1<<n);++i) f[pc(i)][i]=F[i];
			for (int i=0;i<=n;++i) fwt (f[i],1<<n,1);
		}
	    for (int k=0;k<(1<<n);++k){
	    	for(int i=0;i<=n;++i) ff[i]=f[i][k],gg[i]=g[i][k]; 
	    	ll tp;
			for (int i=n;i>=0;--i) {
	    		tp=0;
	        	for (int j=0;j<=i;++j) if (ff[j] && gg[i-j]) tp+=1ll*ff[j]*gg[i-j]%mod;
	            ff[i]=tp%mod;
	    	}
	    	for(int i=0;i<=n;++i) f[i][k]=ff[i];
	    }
	    for (int i=0;i<=n;++i) fwt (f[i],1<<n,-1);
	    for (int i=0;i<(1<<n);++i) H[i]=f[pc(i)][i];
	}

};
using poly::inv;
using poly::exp;
using poly::ln;
using poly::mul;

int n,m,Q;
int sum[M],edg[N];
int pw2[N*N];
int lim[3][N],LIM[3][M];
int lg[M],lbt[M];
int cof[N][M];

inline void init () {
	in (n),in (m),in (Q);
	for (int u,v,i=1;i<=m;++i) {
		in (u),in (v),--u,--v;
		edg[u]|=(1<<v),edg[v]|=(1<<u);
	}
	for (int u,v,c,i=1;i<=Q;++i) {
		in (u),in (v),in (c); --u,--v;
		lim[c][u]|=(1<<v),lim[c][v]|=(1<<u);
	}
	for (int i=2;i<(1<<n);++i) lg[i]=lg[i>>1]+1;
	for (int i=1;i<(1<<n);++i) lbt[i]=(i&(-i));
//	for (int i=1;i<(1<<n);++i) pc[i]=pc[i>>1]+(i&1);
	for (int i=1;i<(1<<n);++i) {
		LIM[1][i]=LIM[1][i^lbt[i]]|lim[1][lg[lbt[i]]];
		LIM[2][i]=LIM[2][i^lbt[i]]|lim[2][lg[lbt[i]]];
	}
	for (int S=1,u;S<(1<<n);++S) {
		u=lg[lbt[S]];
		sum[S]=sum[S^lbt[S]]+pc(edg[lg[lbt[S]]]&S);//内部边数 
	}
	for (int u=0;u<n;++u)
		for (int S=0;S<(1<<n);++S) cof[u][S]=pc(S&(edg[u]&((1<<u)-1)));
	pw2[0]=1; for (int i=1;i<=n*n;++i) pw2[i]=(pw2[i-1]<<1)%mod;
	Inv[1]=1; for (int i=2;i<=n*n;++i) Inv[i]=(1ll*mod-mod/i)*Inv[mod%i]%mod;
}

int dp[M],ndp[M];
int q[M];

inline void solve (int k) {//正向的边双连通-连通变换(割边边权*k) 
	for (int u=0;u<n;++u) {
		for (int S=0;S<(1<<n);++S) q[S]=0;
		for (int S=0;S<(1<<n);++S) if ((!((S>>u)&1)) && dp[S]) q[S]=1ll*k*dp[S]%mod*cof[u][S]%mod;
		exp (n,q,q,1); mul (n,dp,q,ndp,1);
		for (int S=0;S<(1<<n);++S) if ((S>>u)&1) dp[S]=ndp[S];
	}
}
inline void isolve () {//反向的边双连通-连通变换 
	for (int i=0;i<(1<<n);++i) dp[i]=pw2[sum[i]];
	ln (n,dp,dp);
	for (int u=n-1;u>=0;--u) {
		for (int S=0;S<(1<<n);++S) q[S]=0;
		for (int S=0;S<(1<<n);++S) if (!((S>>u)&1)) q[S]=1ll*(mod-1)*dp[S]%mod*cof[u][S]%mod;
		exp (n,q,q,1); mul (n,dp,q,ndp,1);
		for (int S=0;S<(1<<n);++S) if ((S>>u)&1) dp[S]=ndp[S];
	} 
}

int val[M];
inline void work () {
	for (int u=0;u<n;++u) {//计数生成树 
        for (int S=0;S<(1<<u);++S) ndp[S]=1ll*dp[S]*pc(edg[u]&S)%mod;//对于新加入的点u，向之前连好的树连边 
        exp (u,ndp,ndp);//对于这些子树进行无交组合 
        for (int S=0;S<(1<<u);++S) dp[S|(1<<u)]=ndp[S];//贡献到新的答案 
    }
    for (int S=0;S<(1<<n);++S) if (LIM[2][S]&S) dp[S]=0;//不可作极大白色连通块(有c=2限制) 
	solve (mod-1); 
	for (int S=0;S<(1<<n);++S) val[S]=dp[S];
	isolve (); 
	for (int S=0;S<(1<<n);++S) if (pc(S)>1) add (val[S],dp[S]);//大小大于1的边双连通子图 
	for (int S=0;S<(1<<n);++S) dp[S]=val[S];
	solve (1);
	for (int S=0;S<(1<<n);++S) if ((((1<<n)-1)^S)&(LIM[1][S]|LIM[2][S])) dp[S]=0;//有限制在外，不可作一个连通块 
	exp(n,dp,dp);
	printf ("%d\n",dp[(1<<n)-1]);
}
 
int main () {
	init ();
	work ();
	return 0;
}

