#define rep(i,a,b) for(int i=(a);i<=(b);++i)
#define per(i,a,b) for(int i=(a);i>=(b);--i)
#define ll long long
#define pii pair<int,int>
#define pli pair<ll,int>
#define fi first
#define se second
using namespace std;
#define maxn 1001000
int L[maxn],R[maxn];
bool vis[maxn];
vector<ll>A;
#ifdef QwQ
#define ce cerr<<'\n';
#define d(x) cerr<<#x<<":"<<x<<" "
#else
#define ce 0
#define d(x) 0
#endif
void solve(vector<int>d){
	for(int x:d)cerr<<x<<" ";ce;
	int n=d.size();
	d.insert(d.begin(),0);
	d.push_back(0);
	rep(i,1,n)L[i]=i-1,R[i]=i+1;
	R[0]=1,L[n+1]=0,R[n+1]=n+1;
	rep(i,1,n)vis[i]=0;
	priority_queue<pli,vector<pli>,greater<pli>>p;
	rep(i,1,n)p.push({d[i],i});
	rep(_,0,(n+1)/2-1){
		while(vis[p.top().se])p.pop();
		pli t=p.top();
		p.pop();
		int i=t.se;
		int pre=L[i],suf=R[i];
		vis[pre]=vis[suf]=1;
		if(L[i]!=0&&R[i]!=n+1)p.push({d[i]=d[suf]+d[pre]-d[i],i});
		R[i]=R[suf],L[i]=L[pre];
		R[L[i]]=i,L[R[i]]=i;
		if(pre==0)L[R[i]]=0;
		if(suf==n+1)R[L[i]]=n+1;
		A.push_back(t.fi);
		// cerr<<_+1<<":"<<t.fi<<"\n";
		d(i),d(pre),d(L[pre]),d(suf),d(R[suf]),d(L[i]),d(R[i]),ce;
	}
