const int inf = 0x3f3f3f3f;
const int N = 2010;

int n, pos[N], fath[N];
vector<pair<int,int> > g[N];

void work(int x, int fa) {
    fath[x] = fa;
    for(auto temp : g[x]) {
        int y = temp.first;
        if(y == fa) continue;
        work(y, x);
    }
}

struct UFS {
    int fa[N], deg; bool pre[N], nxt[N];
    int get(int x) {
        return fa[x] == x ? x : fa[x] = get(fa[x]);
    }
} S[N];
int fir[N], lst[N];

int query(int x, int fid, int st, int fa)
{
    int res = inf;
    
    if(x != st && !S[x].nxt[fid] && lst[x]==-1) //终点
        if(fir[x]==-1 || S[x].get(fir[x])!=S[x].get(fid) || S[x].deg==1)
            res = min(res, x);

    for(auto temp : g[x])
    {
        int y = temp.first, id = temp.second;
        if(y == fa) continue;

        if (x == st)
        {
            if(S[x].pre[id] || (fir[x]!=-1 && fir[x] != id)) continue;
            if(lst[x]!=-1 && S[x].get(id)==S[x].get(lst[x]) && S[x].deg > 1)
                continue;
        }
        else
        {
            if(S[x].get(id) == S[x].get(fid)) continue;
            if(S[x].pre[id] || S[x].nxt[fid]) continue;
            if(id==fir[x] || fid==lst[x]) continue;
            if(fir[x]!=-1 && lst[x]!=-1 && S[x].deg>2 && 
                S[x].get(fir[x])==S[x].get(fid) && S[x].get(id)==S[x].get(lst[x]))
                continue;
        }

        res = min(res, query(y, id, st, x));
    }

    return res;
}

void change(int x, int st, int en, int fid)
{
    if(x == en) {
        lst[x] = fid; return ;
    }

    for(auto temp : g[x])
    {
        int y = temp.first, id = temp.second;
        if(y != fath[x]) continue;

